// ValidateCreatePolicyRequestBody runs the validations defined on
// CreatePolicyRequestBody
func ValidateCreatePolicyRequestBody(body *CreatePolicyRequestBody) (err error) {
	if body.Name == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("name", "body"))
	}
	if body.NlPrompt == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("nl_prompt", "body"))
	}
	return
}

// ValidateUpdatePolicyRequestBody runs the validations defined on
// UpdatePolicyRequestBody
func ValidateUpdatePolicyRequestBody(body *UpdatePolicyRequestBody) (err error) {
	if body.PolicyID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("policy_id", "body"))
	}
	if body.PolicyID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.policy_id", *body.PolicyID, goa.FormatUUID))
	}
	return
}

// ValidateSetModeRequestBody runs the validations defined on SetModeRequestBody
func ValidateSetModeRequestBody(body *SetModeRequestBody) (err error) {
	if body.PolicyID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("policy_id", "body"))
	}
	if body.Mode == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("mode", "body"))
	}
	if body.PolicyID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.policy_id", *body.PolicyID, goa.FormatUUID))
	}
	if body.Mode != nil {
		if !(*body.Mode == "audit" || *body.Mode == "enforce" || *body.Mode == "disabled") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.mode", *body.Mode, []any{"audit", "enforce", "disabled"}))
		}
	}
	return
}

